// buildChartData ni več potreben — vsaka Line dobi lasten data[]

// ─── Xaxis tick formatter ────────────────────────────────────────────────────
// Slovensko: "2025-07-15 08:30" → "15. 7." za os, "15. 7. 2025" za tooltip
const fmtTick = v => {
  if (!v) return "";
  const [date] = v.split(" ");
  const [, m, d] = date.split("-");
  return `${parseInt(d)}. ${parseInt(m)}.`;
};
const fmtTooltipDate = v => {
  if (!v) return "";
  const [date, time] = v.split(" ");
  const [y, m, d] = date.split("-");
  return `${parseInt(d)}. ${parseInt(m)}. ${y}${time ? ", " + time.slice(0,5) : ""}`;
};

// ─── Tooltip ─────────────────────────────────────────────────────────────────

// ─── En graf — vsaka serija ima lasten data[], brez skupnega merge-a ─────────
// Recharts podpira data prop direktno na <Line> znotraj <ComposedChart>.
// X os je numerična (indeks 0..N), ticki se mapirajo na datume iz najdaljše serije.
function SensorLineChart({ seriesList, unit="", yDomain=["auto","auto"], t }) {
  // Najdaljša serija določa X os tike
  const longest = useMemo(() =>
    seriesList.reduce((a, b) => b.data.length > a.data.length ? b : a, seriesList[0] || { data:[] }),
    [seriesList]
  );

  const ticks = useMemo(() => {
    if (!longest.data.length) return [];
    const n = longest.data.length;
    const step = Math.max(1, Math.floor(n / 7));
    return Array.from({ length: Math.ceil(n / step) }, (_, i) => i * step);
  }, [longest]);

  const tickFormatter = useCallback(idx => {
    const pt = longest.data[idx];
    return pt ? fmtTick(pt.t) : "";
  }, [longest]);

  const tooltipFormatter = useCallback((value, name, props) => {
    return [typeof value === "number" ? value.toFixed(1) + unit : value, name];
  }, [unit]);

  // Tooltip label: poišči timestamp iz najbližje serije
  const tooltipLabelFormatter = useCallback((idx) => {
    for (const s of seriesList) {
      if (s.data[idx]) return fmtTooltipDate(s.data[idx].t);
    }
    return "";
  }, [seriesList]);

  // Vsaka serija: [{index:0,v:23.1}, {index:1,v:23.4}, ...]
  const indexedSeries = useMemo(() =>
    seriesList.map(s => ({
      ...s,
      indexedData: s.data.map((p, i) => ({ i, v: p.v })),
    })),
    [seriesList]
  );

  if (!seriesList.length) return (
    <div style={{height:240,display:"flex",alignItems:"center",justifyContent:"center",
      color:"rgba(255,255,255,0.18)",fontSize:13}}>
      {t('noDataForMonth')}
    </div>
  );

  return (
    <ResponsiveContainer width="100%" height={240}>
      <ComposedChart margin={{top:8,right:12,left:0,bottom:20}}>
        <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" vertical={false} />
        <XAxis
          dataKey="i" type="number"
          ticks={ticks}
          tickFormatter={tickFormatter}
          tick={{fill:"rgba(255,255,255,0.28)",fontSize:10}}
          axisLine={false} tickLine={false}
          domain={[0, longest.data.length - 1]}
          label={{value:t('time'),position:"insideBottom",offset:-12,fill:"rgba(255,255,255,0.2)",fontSize:10.5}}
        />
        <YAxis domain={yDomain}
          tick={{fill:"rgba(255,255,255,0.28)",fontSize:10}}
          tickFormatter={v => v + unit}
          axisLine={false} tickLine={false} width={36}
        />
        <Tooltip
          formatter={tooltipFormatter}
          labelFormatter={tooltipLabelFormatter}
          contentStyle={{
            background:"rgba(18,8,40,0.97)",
            border:"1px solid rgba(255,255,255,0.1)",
            borderRadius:9, fontSize:11.5, color:"#fff",
          }}
          labelStyle={{color:"rgba(255,255,255,0.35)",fontSize:10,marginBottom:4}}
          itemStyle={{color:"#fff"}}
        />
        {indexedSeries.map(s => (
          <Line
            key={s.key}
            data={s.indexedData}
            dataKey="v"
            type="monotone"
            stroke={s.color}
            dot={false}
            strokeWidth={1.8}
            connectNulls={true}
            name={s.name}
            strokeOpacity={0.9}
          />
        ))}
      </ComposedChart>
    </ResponsiveContainer>
  );
}

// ─── Naslov grafa ─────────────────────────────────────────────────────────────
function ChartTitle({ children }) {
  return (
    <p style={{
      margin:"0 0 6px",
      fontSize:11, fontWeight:700,
      color:"rgba(255,255,255,0.38)",
      letterSpacing:"0.08em",
      textTransform:"uppercase",
    }}>{children}</p>
  );
}

// ─── Legenda ──────────────────────────────────────────────────────────────────
function ChartLegend({ seriesList }) {
  return (
    <div style={{display:"flex",flexWrap:"wrap",gap:"5px 14px",marginTop:6,paddingLeft:4}}>
      {seriesList.map(s => (
        <div key={s.key} style={{display:"flex",alignItems:"center",gap:5}}>
          <span style={{width:18,height:2.5,background:s.color,display:"inline-block",borderRadius:2}} />
          <span style={{fontSize:10.5,color:"rgba(255,255,255,0.4)"}}>{s.name}</span>
        </div>
      ))}
    </div>
  );
}

// ─── Pill ─────────────────────────────────────────────────────────────────────
function Pill({ active, dot, label, onClick }) {
  return (
    <button onClick={onClick} style={{
      display:"inline-flex",alignItems:"center",gap:5,
      padding:"4px 11px", borderRadius:20,
      border:`1px solid ${active?"rgba(255,255,255,0.28)":"rgba(255,255,255,0.09)"}`,
      background: active?"rgba(255,255,255,0.09)":"transparent",
      color: active?"rgba(255,255,255,0.85)":"rgba(255,255,255,0.3)",
      fontSize:11.5, cursor:"pointer", fontFamily:"inherit",
      transition:"all 0.15s", whiteSpace:"nowrap",
    }}>
      {dot && <span style={{width:7,height:7,borderRadius:"50%",background:dot,flexShrink:0}} />}
      {label}
    </button>
  );
}

// ─── Graf razdelek ────────────────────────────────────────────────────────────
function ChartBlock({ title, children }) {
  return (
    <div style={{
      background:"rgba(0,0,0,0.13)",
      borderRadius:12,
      padding:"14px 12px 10px",
      marginBottom:10,
    }}>
      <ChartTitle>{title}</ChartTitle>
      {children}
    </div>
  );
}

